const body = $json.body || $json;
const data = body.data || body;
const key = data.key || {};
const msg = data.message || {};
const image = msg.imageMessage || data.imageMessage || {};
return [{ json: { raw: body, instance: body.instance || data.instance || 'loja-descartaveis', remoteJid: key.remoteJid || data.remoteJid || '', mediaUrl: image.url || data.mediaUrl || data.url || '', caption: image.caption || data.caption || '', isFromMe: Boolean(key.fromMe) } }];

const binary = $binary.data;
const mime = binary?.mimeType || 'image/jpeg';
const base64 = binary?.data || '';
const original = $('Normalizar imagem').first().json;
return [{ json: { ...original, imageDataUrl: `data:${mime};base64,${base64}` } }];

const content = $json.choices?.[0]?.message?.content || '{}';
let parsed = {};
try { parsed = JSON.parse(content.replace(/```json|```/g, '').trim()); } catch(e) { parsed = { descricao: content, palavras_chave: content }; }
const termo = Array.isArray(parsed.palavras_chave) ? parsed.palavras_chave.join(' ') : String(parsed.palavras_chave || parsed.descricao || '');
const original = $('Normalizar imagem').first().json;
return [{ json: { ...original, descricaoImagem: parsed.descricao || '', termoBusca: termo } }];

const produtos = $input.all().map(i => i.json);
const original = $('Extrair termos da imagem').first().json;
let resposta = `Analisei a imagem e identifiquei: ${original.descricaoImagem || original.termoBusca}.`;
if (produtos.length) {
  resposta += '\n\nProdutos similares encontrados:\n' + produtos.map((p, i) => `${i + 1}. ${p.name} - R$ ${Number(p.price).toFixed(2)}\n${p.description || ''}`).join('\n\n');
} else {
  resposta += '\n\nNão encontrei um item similar no catálogo. Deseja que eu encaminhe para um atendente verificar?';
}
return [{ json: { instance: original.instance, remoteJid: original.remoteJid, resposta, produtos } }];
